#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <iostream>
#include <string>
#include <omp.h>

#ifdef TIMING
#include <sys/time.h>
#endif

#define MAX_THREADS_PER_BLOCK 256

struct Node {
    int starting;
    int no_of_edges;
};

int work_group_size = 512;
int platform_id_inuse = 0;
int device_id_inuse = 0;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static void tvsub(const struct timeval *t1, const struct timeval *t0, struct timeval *td)
{
    td->tv_sec = t1->tv_sec - t0->tv_sec;
    td->tv_usec = t1->tv_usec - t0->tv_usec;
    if (td->tv_usec < 0) {
        td->tv_sec--;
        td->tv_usec += 1000000;
    }
}
#endif

#ifdef PROFILING
class timer {
public:
    timer(const char * = 0) : start_time(0.0), elapsed(0.0) {}
    timer(const char *, std::ostream &) : start_time(0.0), elapsed(0.0) {}
    ~timer() {}
    void start() { start_time = omp_get_wtime(); }
    void stop() { elapsed += omp_get_wtime() - start_time; }
    void reset() { start_time = 0.0; elapsed = 0.0; }
    double getTimeInSeconds() { return elapsed; }
private:
    double start_time;
    double elapsed;
};
#endif

template<typename datatype>
void compare_results(const datatype *cpu_results, const datatype *gpu_results, const int size)
{
    char passed = true;
    for (int i = 0; i < size; i++) {
        if (cpu_results[i] != gpu_results[i]) {
            passed = false;
        }
    }
    if (passed) {
        std::cout << "--cambine:passed:-)" << std::endl;
    } else {
        std::cout << "--cambine: failed:-(" << std::endl;
    }
}

void _clCmdParams(int argc, char* argv[])
{
    for (int i = 1; i < argc; ++i) {
        if (argv[i][0] != '-' || argv[i][1] == '\0') continue;
        switch (argv[i][1]) {
        case 'g':
            if (++i < argc) {
                sscanf(argv[i], "%u", &work_group_size);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("invalid command line");
            }
            break;
        case 'd':
            if (++i < argc) {
                sscanf(argv[i], "%u", &device_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("invalid command line");
            }
            break;
        case 'p':
            if (++i < argc) {
                sscanf(argv[i], "%u", &platform_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("invalid command line");
            }
            break;
        case 't':
            if (i + 1 < argc) ++i;
            break;
        default:
            break;
        }
    }
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost_ref)
{
    (void)edge_list_size;
    char stop;
    int k = 0;
    do {
        stop = false;
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting;
                     i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while (stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost)
{
    (void)edge_list_size;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
    gettimeofday(&tv_mem_alloc_start, NULL);
    tvsub(&tv_mem_alloc_start, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef PROFILING
    timer kernel_timer;
    double kernel_time_profile = 0.0;
    kernel_timer.reset();
    kernel_timer.start();
#endif

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    char h_over;
    do {
        h_over = false;

        #pragma omp parallel for schedule(static)
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid]) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting;
                     i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        #pragma omp atomic write
                        h_cost[id] = h_cost[tid] + 1;
                        #pragma omp atomic write
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        int over_int = 0;
        #pragma omp parallel for reduction(|:over_int) schedule(static)
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid]) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                over_int = 1;
                h_updating_graph_mask[tid] = false;
            }
        }
        h_over = over_int ? true : false;
    } while (h_over);

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef PROFILING
    kernel_timer.stop();
    kernel_time_profile = kernel_timer.getTimeInSeconds();
    std::cout << "kernel time(s):" << kernel_time_profile << std::endl;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

void Usage(int argc, char **argv)
{
    (void)argc;
    fprintf(stderr, "Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char *argv[])
{
    int no_of_nodes = 0;
    int edge_list_size = 0;
    FILE *fp = NULL;
    Node *h_graph_nodes = NULL;
    char *h_graph_mask = NULL, *h_updating_graph_mask = NULL, *h_graph_visited = NULL;
    int *h_graph_edges = NULL;
    int *h_cost = NULL;
    int *h_cost_ref = NULL;

    try {
        char *input_f;
        if (argc < 2) {
            Usage(argc, argv);
            exit(0);
        }

        _clCmdParams(argc, argv);
        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f, "r");
        if (!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        fscanf(fp, "%d", &no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if (no_of_nodes > MAX_THREADS_PER_BLOCK) {
            num_of_blocks = (int)ceil(no_of_nodes / (double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        (void)num_of_blocks;
        work_group_size = num_of_threads_per_block;

        h_graph_nodes = (Node *)malloc(sizeof(Node) * no_of_nodes);
        h_graph_mask = (char *)malloc(sizeof(char) * no_of_nodes);
        h_updating_graph_mask = (char *)malloc(sizeof(char) * no_of_nodes);
        h_graph_visited = (char *)malloc(sizeof(char) * no_of_nodes);

        int start, edgeno;

        for (int i = 0; i < no_of_nodes; i++) {
            fscanf(fp, "%d %d", &start, &edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        fscanf(fp, "%d", &source);
        source = 0;

        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        fscanf(fp, "%d", &edge_list_size);
        int id, cost;
        h_graph_edges = (int *)malloc(sizeof(int) * edge_list_size);
        for (int i = 0; i < edge_list_size; i++) {
            fscanf(fp, "%d", &id);
            fscanf(fp, "%d", &cost);
            h_graph_edges[i] = id;
        }

        if (fp)
            fclose(fp);
        fp = NULL;

        h_cost = (int *)malloc(sizeof(int) * no_of_nodes);
        h_cost_ref = (int *)malloc(sizeof(int) * no_of_nodes);
        for (int i = 0; i < no_of_nodes; i++) {
            h_cost[i] = -1;
            h_cost_ref[i] = -1;
        }
        h_cost[source] = 0;
        h_cost_ref[source] = 0;

        run_bfs_gpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for (int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        source = 0;
        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        run_bfs_cpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);
    } catch (std::string msg) {
        std::cout << "--cambine: exception in main ->" << msg << std::endl;
        if (fp) fclose(fp);
        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);
    }

    return 0;
}

