#ifdef PROFILING
class timer {
public:
    timer(const char *name = 0) : name(name), write_on_exit(0) { reset(); }
    timer(const char *name, std::ostream &write_on_exit)
        : name(name), write_on_exit(&write_on_exit) { reset(); }
    ~timer() {
        if (write_on_exit != 0) print(*write_on_exit);
    }

    void start() { gettimeofday(&start_tv, 0); }
    void stop() {
        struct timeval end_tv, diff;
        gettimeofday(&end_tv, 0);
        tvsub(&end_tv, &start_tv, &diff);
        total_seconds += diff.tv_sec + diff.tv_usec / 1000000.0;
        ++count;
    }
    void reset() {
        total_seconds = 0.0;
        count = 0;
        start_tv.tv_sec = start_tv.tv_usec = 0;
    }
    std::ostream &print(std::ostream &str) {
        str << std::left << std::setw(25) << (name != 0 ? name : "timer") << ": " << std::right;
        if (count > 0) {
            str << "avg = " << std::setprecision(3) << (total_seconds / static_cast<double>(count))
                << "  s, total = " << total_seconds << "  s, count = " << std::setw(9) << count << '\n';
        } else {
            str << "not used\n";
        }
        return str;
    }
    double getTimeInSeconds() { return total_seconds; }

private:
    double total_seconds;
    unsigned long long count;
    const char *const name;
    std::ostream *const write_on_exit;
    struct timeval start_tv;
};

std::ostream &operator<<(std::ostream &str, class timer &t) {
    return t.print(str);
}
