				factor = 0.5f*normal.y;
				flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
				flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].y+flux_contribution_i_density_energy.y);
				flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].y + flux_contribution_i_momentum_x.y);
				flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].y + flux_contribution_i_momentum_y.y);
				flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].y + flux_contribution_i_momentum_z.y);

				factor = 0.5f*normal.z;
				flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
				flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].z+flux_contribution_i_density_energy.z);
				flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].z + flux_contribution_i_momentum_x.z);
				flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].z + flux_contribution_i_momentum_y.z);
				flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].z + flux_contribution_i_momentum_z.z);
			}
		}

		fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
		fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum.x;
		fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum.y;
		fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum.z;
		fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
	}

#ifdef TIMING
	kernel_time += (gettime() - t1) * 1000.0;
#endif
}

static void kernel_time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes){
#ifdef TIMING
	double t1 = gettime();
#endif
	#pragma omp parallel for
	for(int i = 0; i < nelr; i++){
		float factor = step_factors[i]/(float)(RK+1-j);

		variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
		variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
		variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
		variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];
		variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];
	}
#ifdef TIMING
	kernel_time += (gettime() - t1) * 1000.0;
#endif
}

void initialize_variables(int nelr, cl_mem variables, cl_mem ff_variable){
	kernel_initialize_variables((float*)variables, (const float*)ff_variable, nelr);
}

void compute_step_factor(int nelr, cl_mem variables, cl_mem areas, cl_mem step_factors){
	kernel_compute_step_factor((float*)variables, (float*)areas, (float*)step_factors, nelr);
}

void compute_flux(int nelr, cl_mem elements_surrounding_elements, cl_mem normals, cl_mem variables, cl_mem ff_variable,
                  cl_mem fluxes, cl_mem ff_flux_contribution_density_energy,
                  cl_mem ff_flux_contribution_momentum_x,
                  cl_mem ff_flux_contribution_momentum_y,
                  cl_mem ff_flux_contribution_momentum_z){
	kernel_compute_flux((int*)elements_surrounding_elements, (float*)normals, (float*)variables, (const float*)ff_variable,
	                    (float*)fluxes, (const float3*)ff_flux_contribution_density_energy,
	                    (const float3*)ff_flux_contribution_momentum_x, (const float3*)ff_flux_contribution_momentum_y,
	                    (const float3*)ff_flux_contribution_momentum_z, nelr);
}

void time_step(int j, int nelr, cl_mem old_variables, cl_mem variables, cl_mem step_factors, cl_mem fluxes){
	kernel_time_step(j, nelr, (float*)old_variables, (float*)variables, (float*)step_factors, (float*)fluxes);
}

int main(int argc, char** argv){
	std::printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n", BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

	if (argc < 2){
		std::cout << "specify data file name and [device type] [device id]" << std::endl;
		return 0;
	}
	const char* data_file_name = argv[1];
	_clCmdParams(argc, argv);

	cl_mem ff_variable = NULL, ff_flux_contribution_momentum_x = NULL, ff_flux_contribution_momentum_y = NULL,
	       ff_flux_contribution_momentum_z = NULL, ff_flux_contribution_density_energy = NULL;
	cl_mem areas = NULL, elements_surrounding_elements = NULL, normals = NULL;
	cl_mem variables = NULL, old_variables = NULL, fluxes = NULL, step_factors = NULL;
	float h_ff_variable[NVAR];

	try{
		_clInit(device_type, device_id);

		{
			const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

			h_ff_variable[VAR_DENSITY] = float(1.4);

			float ff_pressure = float(1.0f);
			float ff_speed_of_sound = sqrtf(GAMMA*ff_pressure / h_ff_variable[VAR_DENSITY]);
			float ff_speed = float(ff_mach)*ff_speed_of_sound;

			float3 ff_velocity;
			ff_velocity.x = ff_speed*float(cosf(angle_of_attack));
			ff_velocity.y = ff_speed*float(sinf(angle_of_attack));
			ff_velocity.z = 0.0f;

			h_ff_variable[VAR_MOMENTUM+0] = h_ff_variable[VAR_DENSITY] * ff_velocity.x;
			h_ff_variable[VAR_MOMENTUM+1] = h_ff_variable[VAR_DENSITY] * ff_velocity.y;
			h_ff_variable[VAR_MOMENTUM+2] = h_ff_variable[VAR_DENSITY] * ff_velocity.z;

			h_ff_variable[VAR_DENSITY_ENERGY] = h_ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

			float3 h_ff_momentum;
			h_ff_momentum.x = *(h_ff_variable+VAR_MOMENTUM+0);
			h_ff_momentum.y = *(h_ff_variable+VAR_MOMENTUM+1);
			h_ff_momentum.z = *(h_ff_variable+VAR_MOMENTUM+2);
			float3 h_ff_flux_contribution_momentum_x;
			float3 h_ff_flux_contribution_momentum_y;
			float3 h_ff_flux_contribution_momentum_z;
			float3 h_ff_flux_contribution_density_energy;
			compute_flux_contribution(h_ff_variable[VAR_DENSITY], h_ff_momentum, h_ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity,
			                          &h_ff_flux_contribution_momentum_x, &h_ff_flux_contribution_momentum_y,
			                          &h_ff_flux_contribution_momentum_z, &h_ff_flux_contribution_density_energy);

			ff_variable = _clMalloc(NVAR*sizeof(float));
			ff_flux_contribution_momentum_x = _clMalloc(sizeof(float3));
			ff_flux_contribution_momentum_y = _clMalloc(sizeof(float3));
			ff_flux_contribution_momentum_z = _clMalloc(sizeof(float3));
			ff_flux_contribution_density_energy = _clMalloc(sizeof(float3));
			_clMemcpyH2D(ff_variable, h_ff_variable, NVAR*sizeof(float));
			_clMemcpyH2D(ff_flux_contribution_momentum_x, &h_ff_flux_contribution_momentum_x, sizeof(float3));
			_clMemcpyH2D(ff_flux_contribution_momentum_y, &h_ff_flux_contribution_momentum_y, sizeof(float3));
			_clMemcpyH2D(ff_flux_contribution_momentum_z, &h_ff_flux_contribution_momentum_z, sizeof(float3));
			_clMemcpyH2D(ff_flux_contribution_density_energy, &h_ff_flux_contribution_density_energy, sizeof(float3));
			_clFinish();
		}

		int nel;
		int nelr;

		{
			std::ifstream file(data_file_name);
			if(!file){
				throw(std::string("can not find/open file!"));
			}
			file >> nel;
			nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));
			std::cout<<"--cambine: nel="<<nel<<", nelr="<<nelr<<std::endl;
			float* h_areas = new float[nelr];
			int* h_elements_surrounding_elements = new int[nelr*NNB];
			float* h_normals = new float[nelr*NDIM*NNB];

			for(int i = 0; i < nel; i++)
			{
				file >> h_areas[i];
				for(int j = 0; j < NNB; j++)
				{
					file >> h_elements_surrounding_elements[i + j*nelr];
					if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
					h_elements_surrounding_elements[i + j*nelr]--;

					for(int k = 0; k < NDIM; k++)
					{
						file >> h_normals[i + (j + k*NNB)*nelr];
						h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
					}
				}
			}

			int last = nel-1;
			for(int i = nel; i < nelr; i++)
			{
				h_areas[i] = h_areas[last];
				for(int j = 0; j < NNB; j++)
				{
					h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];
					for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
				}
			}

			areas = alloc<float>(nelr);
			upload<float>(areas, h_areas, nelr);

			elements_surrounding_elements = alloc<int>(nelr*NNB);
			upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr*NNB);

			normals = alloc<float>(nelr*NDIM*NNB);
			upload<float>(normals, h_normals, nelr*NDIM*NNB);

			delete[] h_areas;
			delete[] h_elements_surrounding_elements;
			delete[] h_normals;
		}

		variables = alloc<float>(nelr*NVAR);
		int tp = 0;
		(void)tp;
		initialize_variables(nelr, variables, ff_variable);
		old_variables = alloc<float>(nelr*NVAR);
		fluxes = alloc<float>(nelr*NVAR);
		step_factors = alloc<float>(nelr);

		initialize_variables(nelr, old_variables, ff_variable);
		initialize_variables(nelr, fluxes, ff_variable);
		_clMemset(step_factors, 0, (int)(sizeof(float)*nelr));

		_clFinish();

		std::cout << "Starting..." << std::endl;

		for(int i = 0; i < iterations; i++){
			copy<float>(old_variables, variables, nelr*NVAR);

			compute_step_factor(nelr, variables, areas, step_factors);
			for(int j = 0; j < RK; j++){
				compute_flux(nelr, elements_surrounding_elements, normals, variables, ff_variable, fluxes, ff_flux_contribution_density_energy,
				             ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z);

				time_step(j, nelr, old_variables, variables, step_factors, fluxes);
			}
		}
		_clFinish();
		std::cout << "Saving solution..." << std::endl;
		dump(variables, nel, nelr);
		std::cout << "Saved solution..." << std::endl;
		_clStatistics();
		std::cout << "Cleaning up..." << std::endl;

		_clFree(ff_variable);
		_clFree(ff_flux_contribution_momentum_x);
		_clFree(ff_flux_contribution_momentum_y);
		_clFree(ff_flux_contribution_momentum_z);
		_clFree(ff_flux_contribution_density_energy);
		_clFree(areas);
		_clFree(elements_surrounding_elements);
		_clFree(normals);
		_clFree(variables);
		_clFree(old_variables);
		_clFree(fluxes);
		_clFree(step_factors);
		_clRelease();
		std::cout << "Done..." << std::endl;
		_clPrintTiming();
	}
	catch(std::string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;
		_clFree(ff_variable);
		_clFree(ff_flux_contribution_momentum_x);
		_clFree(ff_flux_contribution_momentum_y);
		_clFree(ff_flux_contribution_momentum_z);
		_clFree(ff_flux_contribution_density_energy);
		_clFree(areas);
		_clFree(elements_surrounding_elements);
		_clFree(normals);
		_clFree(variables);
		_clFree(old_variables);
		_clFree(fluxes);
		_clFree(step_factors);
		_clRelease();
	}
	catch(...){
		std::cout<<"--cambine:( unknow exceptions in main body..."<<std::endl;
		_clFree(ff_variable);
		_clFree(ff_flux_contribution_momentum_x);
		_clFree(ff_flux_contribution_momentum_y);
		_clFree(ff_flux_contribution_momentum_z);
		_clFree(ff_flux_contribution_density_energy);
		_clFree(areas);
		_clFree(elements_surrounding_elements);
		_clFree(normals);
		_clFree(variables);
		_clFree(old_variables);
		_clFree(fluxes);
		_clFree(step_factors);
		_clRelease();
	}

	return 0;
}

#include <iostream>
#include <fstream>
#include <cmath>
#include <cstring>
#include <cstdio>
#include <cstdlib>
#include <algorithm>
#include <string>
#include <omp.h>
#include <sys/time.h>

#ifdef RD_WG_SIZE_0_0
	#define BLOCK_SIZE_0 RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
	#define BLOCK_SIZE_0 RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_0 RD_WG_SIZE
#else
	#define BLOCK_SIZE_0 192
#endif

#ifdef RD_WG_SIZE_1_0
	#define BLOCK_SIZE_1 RD_WG_SIZE_1_0
#elif defined(RD_WG_SIZE_1)
	#define BLOCK_SIZE_1 RD_WG_SIZE_1
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_1 RD_WG_SIZE
#else
	#define BLOCK_SIZE_1 192
#endif

#ifdef RD_WG_SIZE_2_0
	#define BLOCK_SIZE_2 RD_WG_SIZE_2_0
#elif defined(RD_WG_SIZE_1)
	#define BLOCK_SIZE_2 RD_WG_SIZE_2
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_2 RD_WG_SIZE
#else
	#define BLOCK_SIZE_2 192
#endif

#ifdef RD_WG_SIZE_3_0
	#define BLOCK_SIZE_3 RD_WG_SIZE_3_0
#elif defined(RD_WG_SIZE_3)
	#define BLOCK_SIZE_3 RD_WG_SIZE_3
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_3 RD_WG_SIZE
#else
	#define BLOCK_SIZE_3 192
#endif

#ifdef RD_WG_SIZE_4_0
	#define BLOCK_SIZE_4 RD_WG_SIZE_4_0
#elif defined(RD_WG_SIZE_4)
	#define BLOCK_SIZE_4 RD_WG_SIZE_4
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_4 RD_WG_SIZE
#else
	#define BLOCK_SIZE_4 192
#endif

#define GAMMA 1.4f
#define iterations 2000
#ifndef block_length
	#define block_length 192
#endif

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#if block_length > 128
#warning "the kernels may fail too launch on some systems if the block length is too large"
#endif

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

typedef struct{
	float x;
	float y;
	float z;
} float3;

typedef void* cl_mem;

std::string device_type = "";
int device_id = 0;
int platform_id = 0;

void _clCmdParams(int argc, char* argv[]){
	for (int i = 0; i < argc; ++i){
		if (argv[i] == nullptr || argv[i][0] != '-' || argv[i][1] == '\0') continue;
		switch (argv[i][1]){
			case 't':
				if (++i < argc){
					device_type = argv[i];
				}
				else{
					std::cerr << "Could not read argument after option " << argv[i-1] << std::endl;
					throw;
				}
				break;
			case 'd':
				if (++i < argc){
					sscanf(argv[i], "%d", &device_id);
				}
				else{
					std::cerr << "Could not read argument after option " << argv[i-1] << std::endl;
					throw;
				}
				break;
			case 'p':
				if (++i < argc){
					sscanf(argv[i], "%d", &platform_id);
				}
				else{
					std::cerr << "Could not read argument after option " << argv[i-1] << std::endl;
					throw;
				}
				break;
			default:
				;
		}
	}
}

void _clInit(const std::string&, int) {}
void _clRelease() {}
void _clFinish() {}
void _clStatistics() {}
void _clPrintTiming() {}

cl_mem _clMalloc(int size){
	void* p = std::malloc((size_t)size);
	if (!p) throw std::string("could not allocate memory");
	return p;
}

void _clFree(cl_mem ob){
	if (ob != nullptr) std::free(ob);
}

void _clMemcpyH2D(cl_mem dst, const void *src, int size){
	std::memcpy(dst, src, (size_t)size);
}

void _clMemcpyD2H(void * dst, cl_mem src, int size){
	std::memcpy(dst, src, (size_t)size);
}

void _clMemcpyD2D(cl_mem dst, cl_mem src, int size){
	std::memcpy(dst, src, (size_t)size);
}

void _clMemset(cl_mem mem_d, short val, int number_bytes){
	std::memset(mem_d, val, (size_t)number_bytes);
}

template <typename T>
cl_mem alloc(int N){
	cl_mem mem_d = _clMalloc((int)(sizeof(T)*N));
	return mem_d;
}

template <typename T>
void dealloc(cl_mem array){
	_clFree(array);
}

template <typename T>
void copy(cl_mem dst, cl_mem src, int N){
	_clMemcpyD2D(dst, src, (int)(N*sizeof(T)));
}

template <typename T>
void upload(cl_mem dst, T* src, int N){
	_clMemcpyH2D(dst, src, (int)(N*sizeof(T)));
}

template <typename T>
void download(T* dst, cl_mem src, int N){
	_clMemcpyD2H(dst, src, (int)(N*sizeof(T)));
}

void dump(cl_mem variables, int nel, int nelr){
	float* h_variables = new float[nelr*NVAR];
	download(h_variables, variables, nelr*NVAR);

	{
		std::ofstream file("density.txt");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY*nelr] << std::endl;
	}

	{
		std::ofstream file("momentum.txt");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++)
		{
			for(int j = 0; j != NDIM; j++)
				file << h_variables[i + (VAR_MOMENTUM+j)*nelr] << " ";
			file << std::endl;
		}
	}

	{
		std::ofstream file("density_energy.txt");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY_ENERGY*nelr] << std::endl;
	}
	delete[] h_variables;
}

inline void compute_velocity(float density, const float3& momentum, float3& velocity){
	velocity.x = momentum.x / density;
	velocity.y = momentum.y / density;
	velocity.z = momentum.z / density;
}

inline float compute_speed_sqd(const float3& velocity){
	return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

inline float compute_pressure(float density, float density_energy, float speed_sqd){
	return (GAMMA - 1.0f)*(density_energy - 0.5f*density*speed_sqd);
}

inline float compute_speed_of_sound(float density, float pressure){
	return std::sqrt(GAMMA*pressure/density);
}

inline void compute_flux_contribution(const float density, const float3& momentum, const float density_energy, const float pressure, const float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y, float3& fc_momentum_z, float3& fc_density_energy)
{
	(void)density;
	fc_momentum_x.x = velocity.x*momentum.x + pressure;
	fc_momentum_x.y = velocity.x*momentum.y;
	fc_momentum_x.z = velocity.x*momentum.z;

	fc_momentum_y.x = fc_momentum_x.y;
	fc_momentum_y.y = velocity.y*momentum.y + pressure;
	fc_momentum_y.z = velocity.y*momentum.z;

	fc_momentum_z.x = fc_momentum_x.z;
	fc_momentum_z.y = fc_momentum_y.z;
	fc_momentum_z.z = velocity.z*momentum.z + pressure;

	float de_p = density_energy+pressure;
	fc_density_energy.x = velocity.x*de_p;
	fc_density_energy.y = velocity.y*de_p;
	fc_density_energy.z = velocity.z*de_p;
}

void initialize_variables(int nelr, cl_mem variables, cl_mem ff_variable){
	float* variables_p = reinterpret_cast<float*>(variables);
	const float* ff_variable_p = reinterpret_cast<const float*>(ff_variable);

	#pragma omp parallel for
	for(int i = 0; i < nelr; i++){
		for(int j = 0; j < NVAR; j++)
			variables_p[i + j*nelr] = ff_variable_p[j];
	}
}

void compute_step_factor(int nelr, cl_mem variables, cl_mem areas, cl_mem step_factors){
	float* variables_p = reinterpret_cast<float*>(variables);
	float* areas_p = reinterpret_cast<float*>(areas);
	float* step_factors_p = reinterpret_cast<float*>(step_factors);

	#pragma omp parallel for
	for(int i = 0; i < nelr; i++){
		float density = variables_p[i + VAR_DENSITY*nelr];
		float3 momentum;
		momentum.x = variables_p[i + (VAR_MOMENTUM+0)*nelr];
		momentum.y = variables_p[i + (VAR_MOMENTUM+1)*nelr];
		momentum.z = variables_p[i + (VAR_MOMENTUM+2)*nelr];

		float density_energy = variables_p[i + VAR_DENSITY_ENERGY*nelr];

		float3 velocity;
		compute_velocity(density, momentum, velocity);
		float speed_sqd = compute_speed_sqd(velocity);

		float pressure = compute_pressure(density, density_energy, speed_sqd);
		float speed_of_sound = compute_speed_of_sound(density, pressure);

		step_factors_p[i] = 0.5f / (std::sqrt(areas_p[i]) * (std::sqrt(speed_sqd) + speed_of_sound));
	}
}

void compute_flux(int nelr, cl_mem elements_surrounding_elements, cl_mem normals, cl_mem variables, cl_mem ff_variable,
			cl_mem fluxes, cl_mem ff_flux_contribution_density_energy,
			cl_mem ff_flux_contribution_momentum_x,
			cl_mem ff_flux_contribution_momentum_y,
			cl_mem ff_flux_contribution_momentum_z){

	const float smoothing_coefficient = 0.2f;

	int* elements_p = reinterpret_cast<int*>(elements_surrounding_elements);
	float* normals_p = reinterpret_cast<float*>(normals);
	float* variables_p = reinterpret_cast<float*>(variables);
	const float* ff_variable_p = reinterpret_cast<const float*>(ff_variable);
	float* fluxes_p = reinterpret_cast<float*>(fluxes);
	const float3* ff_fc_de = reinterpret_cast<const float3*>(ff_flux_contribution_density_energy);
	const float3* ff_fc_mx = reinterpret_cast<const float3*>(ff_flux_contribution_momentum_x);
	const float3* ff_fc_my = reinterpret_cast<const float3*>(ff_flux_contribution_momentum_y);
	const float3* ff_fc_mz = reinterpret_cast<const float3*>(ff_flux_contribution_momentum_z);

	#pragma omp parallel for
	for(int i = 0; i < nelr; i++){
		int j, nb;
		float3 normal;
		float normal_len;
		float factor;

		float density_i = variables_p[i + VAR_DENSITY*nelr];
		float3 momentum_i;
		momentum_i.x = variables_p[i + (VAR_MOMENTUM+0)*nelr];
		momentum_i.y = variables_p[i + (VAR_MOMENTUM+1)*nelr];
		momentum_i.z = variables_p[i + (VAR_MOMENTUM+2)*nelr];

		float density_energy_i = variables_p[i + VAR_DENSITY_ENERGY*nelr];

		float3 velocity_i;
		compute_velocity(density_i, momentum_i, velocity_i);
		float speed_sqd_i = compute_speed_sqd(velocity_i);

		float speed_i = std::sqrt(speed_sqd_i);
		float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
		float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);
		float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
		float3 flux_contribution_i_density_energy;
		compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
			flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z,
			flux_contribution_i_density_energy);

		float flux_i_density = 0.0f;
		float3 flux_i_momentum;
		flux_i_momentum.x = 0.0f;
		flux_i_momentum.y = 0.0f;
		flux_i_momentum.z = 0.0f;
		float flux_i_density_energy = 0.0f;

		float3 velocity_nb;
		float density_nb, density_energy_nb;
		float3 momentum_nb;
		float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
		float3 flux_contribution_nb_density_energy;
		float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

		for(j = 0; j < NNB; j++)
		{
			nb = elements_p[i + j*nelr];
			normal.x = normals_p[i + (j + 0*NNB)*nelr];
			normal.y = normals_p[i + (j + 1*NNB)*nelr];
			normal.z = normals_p[i + (j + 2*NNB)*nelr];

			normal_len = std::sqrt(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

			if(nb >= 0)
			{
				density_nb = variables_p[nb + VAR_DENSITY*nelr];
				momentum_nb.x = variables_p[nb + (VAR_MOMENTUM+0)*nelr];
				momentum_nb.y = variables_p[nb + (VAR_MOMENTUM+1)*nelr];
				momentum_nb.z = variables_p[nb + (VAR_MOMENTUM+2)*nelr];
				density_energy_nb = variables_p[nb + VAR_DENSITY_ENERGY*nelr];
				compute_velocity(density_nb, momentum_nb, velocity_nb);
				speed_sqd_nb = compute_speed_sqd(velocity_nb);
				pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
				speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);
				compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
					flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z,
					flux_contribution_nb_density_energy);

				factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + std::sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
				flux_i_density += factor*(density_i-density_nb);
				flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
				flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
				flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
				flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

				factor = 0.5f*normal.x;
				flux_i_density += factor*(momentum_nb.x+momentum_i.x);
				flux_i_density_energy += factor*(flux_contribution_nb_density_energy.x+flux_contribution_i_density_energy.x);
				flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.x+flux_contribution_i_momentum_x.x);
				flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.x+flux_contribution_i_momentum_y.x);
				flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.x+flux_contribution_i_momentum_z.x);

				factor = 0.5f*normal.y;
				flux_i_density += factor*(momentum_nb.y+momentum_i.y);
				flux_i_density_energy += factor*(flux_contribution_nb_density_energy.y+flux_contribution_i_density_energy.y);
				flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.y+flux_contribution_i_momentum_x.y);
				flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.y+flux_contribution_i_momentum_y.y);
				flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.y+flux_contribution_i_momentum_z.y);

				factor = 0.5f*normal.z;
				flux_i_density += factor*(momentum_nb.z+momentum_i.z);
				flux_i_density_energy += factor*(flux_contribution_nb_density_energy.z+flux_contribution_i_density_energy.z);
				flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.z+flux_contribution_i_momentum_x.z);
				flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.z+flux_contribution_i_momentum_y.z);
				flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.z+flux_contribution_i_momentum_z.z);
			}
			else if(nb == -1)
			{
				flux_i_momentum.x += normal.x*pressure_i;
				flux_i_momentum.y += normal.y*pressure_i;
				flux_i_momentum.z += normal.z*pressure_i;
			}
			else if(nb == -2)
			{
				factor = 0.5f*normal.x;
				flux_i_density += factor*(ff_variable_p[VAR_MOMENTUM+0]+momentum_i.x);
				flux_i_density_energy += factor*(ff_fc_de[0].x+flux_contribution_i_density_energy.x);
				flux_i_momentum.x += factor*(ff_fc_mx[0].x + flux_contribution_i_momentum_x.x);
				flux_i_momentum.y += factor*(ff_fc_my[0].x + flux_contribution_i_momentum_y.x);
				flux_i_momentum.z += factor*(ff_fc_mz[0].x + flux_contribution_i_momentum_z.x);

				factor = 0.5f*normal.y;
				flux_i_density += factor*(ff_variable_p[VAR_MOMENTUM+1]+momentum_i.y);
				flux_i_density_energy += factor*(ff_fc_de[0].y+flux_contribution_i_density_energy.y);
				flux_i_momentum.x += factor*(ff_fc_mx[0].y + flux_contribution_i_momentum_x.y);
				flux_i_momentum.y += factor*(ff_fc_my[0].y + flux_contribution_i_momentum_y.y);
				flux_i_momentum.z += factor*(ff_fc_mz[0].y + flux_contribution_i_momentum_z.y);

				factor = 0.5f*normal.z;
				flux_i_density += factor*(ff_variable_p[VAR_MOMENTUM+2]+momentum_i.z);
				flux_i_density_energy += factor*(ff_fc_de[0].z+flux_contribution_i_density_energy.z);
				flux_i_momentum.x += factor*(ff_fc_mx[0].z + flux_contribution_i_momentum_x.z);
				flux_i_momentum.y += factor*(ff_fc_my[0].z + flux_contribution_i_momentum_y.z);
				flux_i_momentum.z += factor*(ff_fc_mz[0].z + flux_contribution_i_momentum_z.z);
			}
		}

		fluxes_p[i + VAR_DENSITY*nelr] = flux_i_density;
		fluxes_p[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum.x;
		fluxes_p[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum.y;
		fluxes_p[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum.z;
		fluxes_p[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
	}
}

void time_step(int j, int nelr, cl_mem old_variables, cl_mem variables, cl_mem step_factors, cl_mem fluxes){
	float* old_variables_p = reinterpret_cast<float*>(old_variables);
	float* variables_p = reinterpret_cast<float*>(variables);
	float* step_factors_p = reinterpret_cast<float*>(step_factors);
	float* fluxes_p = reinterpret_cast<float*>(fluxes);

	#pragma omp parallel for
	for(int i = 0; i < nelr; i++){
		float factor = step_factors_p[i]/(float)(RK+1-j);

		variables_p[i + VAR_DENSITY*nelr] = old_variables_p[i + VAR_DENSITY*nelr] + factor*fluxes_p[i + VAR_DENSITY*nelr];
		variables_p[i + VAR_DENSITY_ENERGY*nelr] = old_variables_p[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes_p[i + VAR_DENSITY_ENERGY*nelr];
		variables_p[i + (VAR_MOMENTUM+0)*nelr] = old_variables_p[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes_p[i + (VAR_MOMENTUM+0)*nelr];
		variables_p[i + (VAR_MOMENTUM+1)*nelr] = old_variables_p[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes_p[i + (VAR_MOMENTUM+1)*nelr];
		variables_p[i + (VAR_MOMENTUM+2)*nelr] = old_variables_p[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes_p[i + (VAR_MOMENTUM+2)*nelr];
	}
}

int main(int argc, char** argv){
	printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n", BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

	if (argc < 2){
		std::cout << "specify data file name and [device type] [device id]" << std::endl;
		return 0;
	}
	const char* data_file_name = argv[1];
	_clCmdParams(argc, argv);

	cl_mem ff_variable = nullptr, ff_flux_contribution_momentum_x = nullptr, ff_flux_contribution_momentum_y = nullptr, ff_flux_contribution_momentum_z = nullptr, ff_flux_contribution_density_energy = nullptr;
	cl_mem areas = nullptr, elements_surrounding_elements = nullptr, normals = nullptr;
	cl_mem variables = nullptr, old_variables = nullptr, fluxes = nullptr, step_factors = nullptr;
	float h_ff_variable[NVAR];

	try{
		_clInit(device_type, device_id);

		{
			const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

			h_ff_variable[VAR_DENSITY] = float(1.4);

			float ff_pressure = float(1.0f);
			float ff_speed_of_sound = std::sqrt(GAMMA*ff_pressure / h_ff_variable[VAR_DENSITY]);
			float ff_speed = float(ff_mach)*ff_speed_of_sound;

			float3 ff_velocity;
			ff_velocity.x = ff_speed*float(std::cos((float)angle_of_attack));
			ff_velocity.y = ff_speed*float(std::sin((float)angle_of_attack));
			ff_velocity.z = 0.0f;

			h_ff_variable[VAR_MOMENTUM+0] = h_ff_variable[VAR_DENSITY] * ff_velocity.x;
			h_ff_variable[VAR_MOMENTUM+1] = h_ff_variable[VAR_DENSITY] * ff_velocity.y;
			h_ff_variable[VAR_MOMENTUM+2] = h_ff_variable[VAR_DENSITY] * ff_velocity.z;

			h_ff_variable[VAR_DENSITY_ENERGY] = h_ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

			float3 h_ff_momentum;
			h_ff_momentum.x = *(h_ff_variable+VAR_MOMENTUM+0);
			h_ff_momentum.y = *(h_ff_variable+VAR_MOMENTUM+1);
			h_ff_momentum.z = *(h_ff_variable+VAR_MOMENTUM+2);
			float3 h_ff_flux_contribution_momentum_x;
			float3 h_ff_flux_contribution_momentum_y;
			float3 h_ff_flux_contribution_momentum_z;
			float3 h_ff_flux_contribution_density_energy;
			compute_flux_contribution(h_ff_variable[VAR_DENSITY], h_ff_momentum, h_ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity,
				h_ff_flux_contribution_momentum_x, h_ff_flux_contribution_momentum_y, h_ff_flux_contribution_momentum_z, h_ff_flux_contribution_density_energy);

			ff_variable = _clMalloc(NVAR*sizeof(float));
			ff_flux_contribution_momentum_x = _clMalloc(sizeof(float3));
			ff_flux_contribution_momentum_y = _clMalloc(sizeof(float3));
			ff_flux_contribution_momentum_z = _clMalloc(sizeof(float3));
			ff_flux_contribution_density_energy = _clMalloc(sizeof(float3));
			_clMemcpyH2D(ff_variable, h_ff_variable, NVAR*sizeof(float));
			_clMemcpyH2D(ff_flux_contribution_momentum_x, &h_ff_flux_contribution_momentum_x, sizeof(float3));
			_clMemcpyH2D(ff_flux_contribution_momentum_y, &h_ff_flux_contribution_momentum_y, sizeof(float3));
			_clMemcpyH2D(ff_flux_contribution_momentum_z, &h_ff_flux_contribution_momentum_z, sizeof(float3));
			_clMemcpyH2D(ff_flux_contribution_density_energy, &h_ff_flux_contribution_density_energy, sizeof(float3));
			_clFinish();
		}

		int nel;
		int nelr;

		{
			std::ifstream file(data_file_name);
			if(!file){
				throw(std::string("can not find/open file!"));
			}
			file >> nel;
			nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));
			std::cout<<"--cambine: nel="<<nel<<", nelr="<<nelr<<std::endl;
			float* h_areas = new float[nelr];
			int* h_elements_surrounding_elements = new int[nelr*NNB];
			float* h_normals = new float[nelr*NDIM*NNB];

			for(int i = 0; i < nel; i++)
			{
				file >> h_areas[i];
				for(int j = 0; j < NNB; j++)
				{
					file >> h_elements_surrounding_elements[i + j*nelr];
					if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
					h_elements_surrounding_elements[i + j*nelr]--;

					for(int k = 0; k < NDIM; k++)
					{
						file >> h_normals[i + (j + k*NNB)*nelr];
						h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
					}
				}
			}

			int last = nel-1;
			for(int i = nel; i < nelr; i++)
			{
				h_areas[i] = h_areas[last];
				for(int j = 0; j < NNB; j++)
				{
					h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];
					for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
				}
			}

			areas = alloc<float>(nelr);
			upload<float>(areas, h_areas, nelr);

			elements_surrounding_elements = alloc<int>(nelr*NNB);
			upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr*NNB);

			normals = alloc<float>(nelr*NDIM*NNB);
			upload<float>(normals, h_normals, nelr*NDIM*NNB);

			delete[] h_areas;
			delete[] h_elements_surrounding_elements;
			delete[] h_normals;
		}

		variables = alloc<float>(nelr*NVAR);
		int tp = 0;
		(void)tp;
		initialize_variables(nelr, variables, ff_variable);
		old_variables = alloc<float>(nelr*NVAR);
		fluxes = alloc<float>(nelr*NVAR);
		step_factors = alloc<float>(nelr);

		initialize_variables(nelr, old_variables, ff_variable);
		initialize_variables(nelr, fluxes, ff_variable);
		_clMemset(step_factors, 0, (int)(sizeof(float)*nelr));

		_clFinish();

		std::cout << "Starting..." << std::endl;

		for(int i = 0; i < iterations; i++){
			copy<float>(old_variables, variables, nelr*NVAR);

			compute_step_factor(nelr, variables, areas, step_factors);
			for(int j = 0; j < RK; j++){
				compute_flux(nelr, elements_surrounding_elements, normals, variables, ff_variable, fluxes, ff_flux_contribution_density_energy,
					ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z);

				time_step(j, nelr, old_variables, variables, step_factors, fluxes);
			}
		}
		_clFinish();
		std::cout << "Saving solution..." << std::endl;
		dump(variables, nel, nelr);
		std::cout << "Saved solution..." << std::endl;
		_clStatistics();
		std::cout << "Cleaning up..." << std::endl;

		_clFree(ff_variable);
		_clFree(ff_flux_contribution_momentum_x);
		_clFree(ff_flux_contribution_momentum_y);
		_clFree(ff_flux_contribution_momentum_z);
		_clFree(ff_flux_contribution_density_energy);
		_clFree(areas);
		_clFree(elements_surrounding_elements);
		_clFree(normals);
		_clFree(variables);
		_clFree(old_variables);
		_clFree(fluxes);
		_clFree(step_factors);
		_clRelease();
		std::cout << "Done..." << std::endl;
		_clPrintTiming();
	}
	catch(std::string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;
		_clFree(ff_variable);
		_clFree(ff_flux_contribution_momentum_x);
		_clFree(ff_flux_contribution_momentum_y);
		_clFree(ff_flux_contribution_momentum_z);
		_clFree(ff_flux_contribution_density_energy);
		_clFree(areas);
		_clFree(elements_surrounding_elements);
		_clFree(normals);
		_clFree(variables);
		_clFree(old_variables);
		_clFree(fluxes);
		_clFree(step_factors);
		_clRelease();
	}
	catch(...){
		std::cout<<"--cambine:( unknow exceptions in main body..."<<std::endl;
		_clFree(ff_variable);
		_clFree(ff_flux_contribution_momentum_x);
		_clFree(ff_flux_contribution_momentum_y);
		_clFree(ff_flux_contribution_momentum_z);
		_clFree(ff_flux_contribution_density_energy);
		_clFree(areas);
		_clFree(elements_surrounding_elements);
		_clFree(normals);
		_clFree(variables);
		_clFree(old_variables);
		_clFree(fluxes);
		_clFree(step_factors);
		_clRelease();
	}

	return 0;
}

#include <iostream>
#include <fstream>
#include <math.h>
#include <omp.h>
#include <sys/time.h>
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <string>
#include <algorithm>

#ifdef RD_WG_SIZE_0_0
	#define BLOCK_SIZE_0 RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
	#define BLOCK_SIZE_0 RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_0 RD_WG_SIZE
#else
	#define BLOCK_SIZE_0 192
#endif

#ifdef RD_WG_SIZE_1_0
	#define BLOCK_SIZE_1 RD_WG_SIZE_1_0
#elif defined(RD_WG_SIZE_1)
	#define BLOCK_SIZE_1 RD_WG_SIZE_1
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_1 RD_WG_SIZE
#else
	#define BLOCK_SIZE_1 192
#endif

#ifdef RD_WG_SIZE_2_0
	#define BLOCK_SIZE_2 RD_WG_SIZE_2_0
#elif defined(RD_WG_SIZE_1)
	#define BLOCK_SIZE_2 RD_WG_SIZE_2
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_2 RD_WG_SIZE
#else
	#define BLOCK_SIZE_2 192
#endif

#ifdef RD_WG_SIZE_3_0
	#define BLOCK_SIZE_3 RD_WG_SIZE_3_0
#elif defined(RD_WG_SIZE_3)
	#define BLOCK_SIZE_3 RD_WG_SIZE_3
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_3 RD_WG_SIZE
#else
	#define BLOCK_SIZE_3 192
#endif

#ifdef RD_WG_SIZE_4_0
	#define BLOCK_SIZE_4 RD_WG_SIZE_4_0
#elif defined(RD_WG_SIZE_4)
	#define BLOCK_SIZE_4 RD_WG_SIZE_4
#elif defined(RD_WG_SIZE)
	#define BLOCK_SIZE_4 RD_WG_SIZE
#else
	#define BLOCK_SIZE_4 192
#endif

#define GAMMA 1.4f
#define iterations 2000
#ifndef block_length
	#define block_length 192
#endif

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#if block_length > 128
#warning "the kernels may fail too launch on some systems if the block length is too large"
#endif

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

typedef struct{
	float x;
	float y;
	float z;
} float3;

typedef void* cl_mem;

std::string device_type = "";
int device_id = 0;
int platform_id = 0;

template <typename T>
cl_mem alloc(int N){
	return (cl_mem)malloc(sizeof(T) * N);
}

template <typename T>
void dealloc(cl_mem array){
	free(array);
}

template <typename T>
void copy(cl_mem dst, cl_mem src, int N){
	memcpy(dst, src, N * sizeof(T));
}

template <typename T>
void upload(cl_mem dst, T* src, int N){
	memcpy(dst, src, N * sizeof(T));
}

template <typename T>
void download(T* dst, cl_mem src, int N){
	memcpy(dst, src, N * sizeof(T));
}

void _clCmdParams(int argc, char* argv[]){
	for (int i = 0; i < argc; ++i){
		if (argv[i][0] != '-') continue;
		switch (argv[i][1]){
			case 't':
				if (++i < argc){
					device_type = argv[i];
				}
				else{
					std::cerr << "Could not read argument after option " << argv[i-1] << std::endl;
					throw;
				}
				break;
			case 'd':
				if (++i < argc){
					sscanf(argv[i], "%d", &device_id);
				}
				else{
					std::cerr << "Could not read argument after option " << argv[i-1] << std::endl;
					throw;
				}
				break;
			case 'p':
				if (++i < argc){
					sscanf(argv[i], "%d", &platform_id);
				}
				else{
					std::cerr << "Could not read argument after option " << argv[i-1] << std::endl;
					throw;
				}
				break;
			default:
				;
		}
	}
}

