#define MAX_PD   (3.0e6)

#define PRECISION    0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI         100

#define FACTOR_CHIP  0.5

#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)

float t_chip      = 0.0005f;
float chip_height = 0.016f;
float chip_width  = 0.016f;
float amb_temp    = 80.0f;

static void tvsub(const struct timeval *x, const struct timeval *y, struct timeval *res)
{
    res->tv_sec = x->tv_sec - y->tv_sec;
    res->tv_usec = x->tv_usec - y->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}

static float my_sqrtf(float x)
{
    if (x <= 0.0f) return 0.0f;
    float g = (x > 1.0f) ? x : 1.0f;
    for (int i = 0; i < 20; i++) {
        g = 0.5f * (g + x / g);
    }
    return g;
}

