static void hotspotOpt1_omp(float *p, float *tIn, float *tOut, float sdc,
                            int nx, int ny, int nz,
                            float ce, float cw,
                            float cn, float cs,
                            float ct, float cb,
                            float cc)
{
    const float amb_temp_local = 80.0f;
    const int xy = nx * ny;

    #pragma omp parallel for collapse(2)
    for (int j = 0; j < ny; j++) {
        for (int i = 0; i < nx; i++) {
            int c = i + j * nx;
            int W = (i == 0) ? c : c - 1;
