            int N = (j == 0) ? c : c - nx;
            int S = (ny - 1 == j) ? c : c + nx;

            float temp1, temp2, temp3;

            if (nz == 1) {
                temp1 = temp2 = tIn[c];
                temp3 = tIn[c];
                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
                continue;
            }

            temp1 = temp2 = tIn[c];
            temp3 = tIn[c + xy];
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;

            c += xy;
            W += xy;
            E += xy;
            N += xy;
            S += xy;

            for (int k = 1; nz - 1 > k; ++k) {
                temp1 = temp2;
                temp2 = temp3;
                temp3 = tIn[c + xy];
                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
                c += xy;
                W += xy;
                E += xy;
                N += xy;
                S += xy;
            }

            temp1 = temp2;
            temp2 = temp3;
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
        }
    }
}

