#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <sys/time.h>

#ifdef _OPENMP
#include <omp.h>
#endif

#define fp float

#ifdef RD_WG_SIZE_0_0
    #define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
    #define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
    #define NUMBER_THREADS RD_WG_SIZE
#else
    #define NUMBER_THREADS 256
#endif

int platform_id_inuse = 0;
int device_id_inuse = 0;

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

#ifdef TIMING
static void tvsub(const struct timeval *x, const struct timeval *y, struct timeval *out) {
    out->tv_sec = x->tv_sec - y->tv_sec;
    out->tv_usec = x->tv_usec - y->tv_usec;
    if (out->tv_usec < 0) {
        out->tv_sec--;
        out->tv_usec += 1000000;
    }
}
#endif

void
write_graphics(char* filename,
               fp* input,
               int data_rows,
               int data_cols,
               int major,
               int data_range) {

    FILE* fid;
    int i, j;

    fid = fopen(filename, "w");
    if (fid == NULL) {
        printf("The file was not created/opened for writing\n");
        return;
    }

    fprintf(fid, "P2\n");
    fprintf(fid, "%d %d\n", data_cols, data_rows);
    fprintf(fid, "%d\n", data_range);

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fprintf(fid, "%d ", (int)input[i * data_cols + j]);
            }
            fprintf(fid, "\n");
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fprintf(fid, "%d ", (int)input[j * data_rows + i]);
            }
            fprintf(fid, "\n");
        }
    }

    fclose(fid);
}

void
read_graphics(char* filename,
              fp* input,
              int data_rows,
              int data_cols,
              int major) {

    FILE* fid;
    int i, j;
    char c;
    int temp;

    fid = fopen(filename, "r");
    if (fid == NULL) {
        printf("The file was not opened for reading\n");
        return;
    }

    i = 0;
    while (i < 3) {
        c = (char)fgetc(fid);
        if (c == '\n') {
            i = i + 1;
        }
    }

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%d", &temp);
                input[i * data_cols + j] = (fp)temp;
            }
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%d", &temp);
                input[j * data_rows + i] = (fp)temp;
            }
        }
    }

    fclose(fid);
}

void
resize(fp* input,
       int input_rows,
       int input_cols,
       fp* output,
       int output_rows,
       int output_cols,
       int major) {

    int i, j;
    int i2, j2;

    if (major == 0) {
        for (i = 0, i2 = 0; i < output_rows; i++, i2++) {
            if (i2 >= input_rows) {
                i2 = i2 - input_rows;
            }
            for (j = 0, j2 = 0; j < output_cols; j++, j2++) {
                if (j2 >= input_cols) {
                    j2 = j2 - input_cols;
                }
                output[i * output_cols + j] = input[i2 * input_cols + j2];
            }
        }
    } else {
        for (j = 0, j2 = 0; j < output_cols; j++, j2++) {
            if (j2 >= input_cols) {
                j2 = j2 - input_cols;
            }
            for (i = 0, i2 = 0; i < output_rows; i++, i2++) {
                if (i2 >= input_rows) {
                    i2 = i2 - input_rows;
                }
                output[j * output_rows + i] = input[j2 * input_rows + i2];
            }
        }
    }
}

static void
extract_kernel(long d_Ne,
               fp* d_I) {
#pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = expf(d_I[ei] / 255.0f);
    }
}

static void
prepare_kernel(long d_Ne,
               fp* d_I,
               fp* d_sums,
               fp* d_sums2) {
#pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

static void
reduce_kernel(long d_Ne,
              long d_no,
              int d_mul,
              fp* d_sums,
              fp* d_sums2,
              int gridDim) {
    (void)d_Ne;

    int bx;
    int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - (int)d_no);

#pragma omp parallel for private(bx) schedule(static)
    for (bx = 0; bx < gridDim; bx++) {
        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];
        int tx;
        int i;
        int df = 0;

        for (tx = 0; tx < NUMBER_THREADS; tx++) {
            long ei = (long)bx * NUMBER_THREADS + tx;
            if (ei < d_no) {
                d_psum[tx] = d_sums[ei * d_mul];
                d_psum2[tx] = d_sums2[ei * d_mul];
            } else {
                d_psum[tx] = 0;
                d_psum2[tx] = 0;
            }
        }

        if (nf == NUMBER_THREADS) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                for (tx = 0; tx < NUMBER_THREADS; tx++) {
                    if ((tx + 1) % i == 0) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                    }
                }
            }

            d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
            d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
        } else {
            if (bx != (gridDim - 1)) {
                for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    for (tx = 0; tx < NUMBER_THREADS; tx++) {
                        if ((tx + 1) % i == 0) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                        }
                    }
                }

                d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
                d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
            } else {
                for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    if (nf >= i) {
                        df = i;
                    }
                }

                for (i = 2; i <= df; i = 2 * i) {
                    for (tx = 0; tx < NUMBER_THREADS; tx++) {
                        if ((tx + 1) % i == 0 && tx < df) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                        }
                    }
                }

                if (df > 0) {
                    for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                        d_psum[df - 1] = d_psum[df - 1] + d_sums[i];
                        d_psum2[df - 1] = d_psum2[df - 1] + d_sums2[i];
                    }

                    d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[df - 1];
                    d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[df - 1];
                }
            }
        }
    }
}

static void
srad_kernel(fp d_lambda,
            int d_Nr,
            int d_Nc,
            long d_Ne,
            int* d_iN,
            int* d_iS,
            int* d_jE,
            int* d_jW,
            fp* d_dN,
            fp* d_dS,
            fp* d_dE,
            fp* d_dW,
            fp d_q0sqr,
            fp* d_c,
            fp* d_I) {
    (void)d_lambda;
    (void)d_Nc;

#pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row;
        int col;

        fp d_Jc;
        fp d_dN_loc, d_dS_loc, d_dW_loc, d_dE_loc;
        fp d_c_loc;
        fp d_G2, d_L, d_num, d_den, d_qsqr;

        row = (int)((ei + 1) % d_Nr - 1);
        col = (int)((ei + 1) / d_Nr + 1 - 1);
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        d_Jc = d_I[ei];

        d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);

        d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
        d_den = 1.0f + (0.25f * d_L);
        d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1.0f + d_q0sqr));
        d_c_loc = 1.0f / (1.0f + d_den);

        if (d_c_loc < 0) {
            d_c_loc = 0;
        } else if (d_c_loc > 1) {
            d_c_loc = 1;
        }

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }
}

static void
srad2_kernel(fp d_lambda,
             int d_Nr,
             int d_Nc,
             long d_Ne,
             int* d_iN,
             int* d_iS,
             int* d_jE,
             int* d_jW,
             fp* d_dN,
             fp* d_dS,
             fp* d_dE,
             fp* d_dW,
             fp* d_c,
             fp* d_I) {
    (void)d_Nc;
    (void)d_iN;
    (void)d_jW;

#pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row;
        int col;

        fp d_cN, d_cS, d_cW, d_cE;
        fp d_D;

        row = (int)((ei + 1) % d_Nr - 1);
        col = (int)((ei + 1) / d_Nr + 1 - 1);
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        d_cN = d_c[ei];
        d_cS = d_c[d_iS[row] + d_Nr * col];
        d_cW = d_c[ei];
        d_cE = d_c[row + d_Nr * d_jE[col]];

        d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25f * d_lambda * d_D;
    }
}

static void
compress_kernel(long d_Ne,
                fp* d_I) {
#pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = logf(d_I[ei]) * 255.0f;
    }
}

void
kernel_gpu_opencl_wrapper(fp* image,
                          int Nr,
                          int Nc,
                          long Ne,
                          int niter,
                          fp lambda,
                          long NeROI,
                          int* iN,
                          int* iS,
                          int* jE,
                          int* jW,
                          int iter,
                          int mem_size_i,
                          int mem_size_j) {

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

    printf("Platform: %s\n", "OpenMP");
    printf("Device: %s\n", "CPU");
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    int blocks_x;

    int mem_size;
    mem_size = (int)(sizeof(fp) * Ne);

    fp* d_I = (fp*)malloc(mem_size);
    int* d_iN = (int*)malloc(mem_size_i);
    int* d_iS = (int*)malloc(mem_size_i);
    int* d_jE = (int*)malloc(mem_size_j);
    int* d_jW = (int*)malloc(mem_size_j);

    fp* d_dN = (fp*)malloc(mem_size);
    fp* d_dS = (fp*)malloc(mem_size);
    fp* d_dW = (fp*)malloc(mem_size);
    fp* d_dE = (fp*)malloc(mem_size);

    fp* d_c = (fp*)malloc(mem_size);

    fp* d_sums = (fp*)malloc(mem_size);
    fp* d_sums2 = (fp*)malloc(mem_size);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_h2d_start, NULL);
#endif

    memcpy(d_I, image, mem_size);
    memcpy(d_iN, iN, mem_size_i);
    memcpy(d_iS, iS, mem_size_i);
    memcpy(d_jE, jE, mem_size_j);
    memcpy(d_jW, jW, mem_size_j);

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    size_t local_work_size[1];
    local_work_size[0] = NUMBER_THREADS;

    int blocks_work_size;
    size_t global_work_size[1];
    blocks_x = (int)(Ne / (long)local_work_size[0]);
    if (Ne % (long)local_work_size[0] != 0) {
        blocks_x = blocks_x + 1;
    }
    blocks_work_size = blocks_x;
    global_work_size[0] = (size_t)blocks_work_size * local_work_size[0];

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
           (int)(global_work_size[0] / local_work_size[0]),
           (int)local_work_size[0]);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif
    extract_kernel(Ne, d_I);
#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    int blocks2_work_size;
    size_t global_work_size2[1];
    long no;
    int mul;
    int mem_size_single = (int)(sizeof(fp) * 1);
    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;
    (void)mem_size_single;

    printf("Iterations Progress: hidden");

    for (iter = 0; iter < niter; iter++) {
        fflush(NULL);

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        prepare_kernel(Ne, d_I, d_sums, d_sums2);
#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        blocks2_work_size = blocks_work_size;
        global_work_size2[0] = global_work_size[0];
        no = Ne;
        mul = 1;

        while (blocks2_work_size != 0) {
#ifdef TIMING
            gettimeofday(&tv_kernel_start, NULL);
#endif
            reduce_kernel(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);
#ifdef TIMING
            gettimeofday(&tv_kernel_end, NULL);
            tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
            kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / (int)local_work_size[0];
                if (blocks2_work_size % (int)local_work_size[0] != 0) {
                    blocks_x = blocks_x + 1;
                }
                blocks2_work_size = blocks_x;
                global_work_size2[0] = (size_t)blocks2_work_size * (int)local_work_size[0];
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        srad_kernel(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, q0sqr, d_c, d_I);
#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        srad2_kernel(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, d_c, d_I);
#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
    }

    printf("\n");

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif
    compress_kernel(Ne, d_I);
#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_d2h_start, NULL);
#endif

    memcpy(image, d_I, mem_size);

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_close_start, NULL);
#endif

    free(d_I);
    free(d_c);

    free(d_iN);
    free(d_iS);
    free(d_jE);
    free(d_jW);

    free(d_dN);
    free(d_dS);
    free(d_dE);
    free(d_dW);

    free(d_sums);
    free(d_sums2);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    printf("Time spent in different stages of the application:\n");
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

int
main(int argc,
     char* argv[]) {
    printf("WG size of kernel = %d \n", NUMBER_THREADS);

    fp* image_ori;
    int image_ori_rows;
    int image_ori_cols;
    long image_ori_elem;

    fp* image;
    int Nr, Nc;
    long Ne;

    int niter;
    fp lambda;

    int r1, r2, c1, c2;
    long NeROI;

    int* iN;
    int* iS;
    int* jE;
    int* jW;

    int iter;
    long i;
    long j;

    int mem_size_i;
    int mem_size_j;

    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                niter = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                lambda = (fp)atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (argc >= cur_arg + 3) {
                Nr = atoi(argv[cur_arg + 1]);
                Nc = atoi(argv[cur_arg + 2]);
                cur_arg = cur_arg + (2);
            }
        } else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    image_ori_rows = 502;
    image_ori_cols = 458;
    image_ori_elem = (long)image_ori_rows * image_ori_cols;

    image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

    read_graphics((char*)"../../data/srad/image.pgm",
                  image_ori,
                  image_ori_rows,
                  image_ori_cols,
                  1);

    Ne = (long)Nr * Nc;

    image = (fp*)malloc(sizeof(fp) * Ne);

    resize(image_ori,
           image_ori_rows,
           image_ori_cols,
           image,
           Nr,
           Nc,
           1);

    r1 = 0;
    r2 = Nr - 1;
    c1 = 0;
    c2 = Nc - 1;

    NeROI = (long)(r2 - r1 + 1) * (c2 - c1 + 1);

    mem_size_i = sizeof(int) * Nr;
    iN = (int*)malloc(mem_size_i);
    iS = (int*)malloc(mem_size_i);
    mem_size_j = sizeof(int) * Nc;
    jW = (int*)malloc(mem_size_j);
    jE = (int*)malloc(mem_size_j);

    for (i = 0; i < Nr; i++) {
        iN[i] = (int)i - 1;
        iS[i] = (int)i + 1;
    }
    for (j = 0; j < Nc; j++) {
        jW[j] = (int)j - 1;
        jE[j] = (int)j + 1;
    }

    iN[0] = 0;
    iS[Nr - 1] = Nr - 1;
    jW[0] = 0;
    jE[Nc - 1] = Nc - 1;

    kernel_gpu_opencl_wrapper(image,
                              Nr,
                              Nc,
                              Ne,
                              niter,
                              lambda,
                              NeROI,
                              iN,
                              iS,
                              jE,
                              jW,
                              iter,
                              mem_size_i,
                              mem_size_j);

    write_graphics((char*)"./output/image_out.pgm",
                   image,
                   Nr,
                   Nc,
                   1,
                   255);

    free(image_ori);
    free(image);
    free(iN);
    free(iS);
    free(jW);
    free(jE);

    return 0;
}

#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <sys/time.h>
#include <omp.h>

#define fp float

#ifdef RD_WG_SIZE_0_0
#define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define NUMBER_THREADS RD_WG_SIZE
#else
#define NUMBER_THREADS 256
#endif

int platform_id_inuse = 0;
int device_id_inuse = 0;

static void write_graphics(const char* filename,
                           fp* input,
                           int data_rows,
                           int data_cols,
                           int major,
                           int data_range) {
    FILE* fid;
    int i, j;

    fid = fopen(filename, "w");
    if (fid == NULL) {
        printf("The file was not created/opened for writing\n");
        return;
    }

    fprintf(fid, "P2\n");
    fprintf(fid, "%d %d\n", data_cols, data_rows);
    fprintf(fid, "%d\n", data_range);

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fprintf(fid, "%d ", (int)input[i * data_cols + j]);
            }
            fprintf(fid, "\n");
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fprintf(fid, "%d ", (int)input[j * data_rows + i]);
            }
            fprintf(fid, "\n");
        }
    }

    fclose(fid);
}

static void read_graphics(const char* filename,
                          fp* input,
                          int data_rows,
                          int data_cols,
                          int major) {
    FILE* fid;
    int i, j;
    char c;
    int temp;

    fid = fopen(filename, "r");
    if (fid == NULL) {
        printf("The file was not opened for reading\n");
        return;
    }

    i = 0;
    while (i < 3) {
        c = fgetc(fid);
        if (c == '\n') {
            i = i + 1;
        }
    }

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%d", &temp);
                input[i * data_cols + j] = (fp)temp;
            }
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%d", &temp);
                input[j * data_rows + i] = (fp)temp;
            }
        }
    }

    fclose(fid);
}

static void resize(fp* input,
                   int input_rows,
                   int input_cols,
                   fp* output,
                   int output_rows,
                   int output_cols,
                   int major) {
    int i, j;
    int i2, j2;

    if (major == 0) {
        for (i = 0, i2 = 0; i < output_rows; i++, i2++) {
            if (i2 >= input_rows) {
                i2 = i2 - input_rows;
            }
            for (j = 0, j2 = 0; j < output_cols; j++, j2++) {
                if (j2 >= input_cols) {
                    j2 = j2 - input_cols;
                }
                output[i * output_cols + j] = input[i2 * input_cols + j2];
            }
        }
    } else {
        for (j = 0, j2 = 0; j < output_cols; j++, j2++) {
            if (j2 >= input_cols) {
                j2 = j2 - input_cols;
            }
            for (i = 0, i2 = 0; i < output_rows; i++, i2++) {
                if (i2 >= input_rows) {
                    i2 = i2 - input_rows;
                }
                output[j * output_rows + i] = input[j2 * input_rows + i2];
            }
        }
    }
}

#ifdef TIMING
static void tvsub(const struct timeval* t1, const struct timeval* t0, struct timeval* td) {
    td->tv_sec = t1->tv_sec - t0->tv_sec;
    td->tv_usec = t1->tv_usec - t0->tv_usec;
    if (td->tv_usec < 0) {
        td->tv_usec += 1000000;
        td->tv_sec--;
    }
}
#endif

