                              iS,
                              jE,
                              jW,
                              iter,
                              mem_size_i,
                              mem_size_j);

    write_graphics((char*)"./output/image_out.pgm",
                   image,
                   Nr,
                   Nc,
                   1,
                   255);

    free(image_ori);
    free(image);
    free(iN);
    free(iS);
    free(jW);
    free(jE);

    return 0;
}

