static double fast_exp(double x)
{
	x = 1.0 + x * 0.000244140625;
	x = x * x; x = x * x; x = x * x; x = x * x;
	x = x * x; x = x * x; x = x * x; x = x * x;
	x = x * x; x = x * x; x = x * x; x = x * x;
	return x;
}

double LCG_random_double(uint64_t * seed)
{
	const uint64_t m = 9223372036854775808ULL;
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	*seed = (a * (*seed) + c) % m;
	return (double) (*seed) / (double) m;
}

uint64_t LCG_random_int(uint64_t * seed)
{
	const uint64_t m = 9223372036854775808ULL;
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	*seed = (a * (*seed) + c) % m;
	return *seed;
}

uint64_t fast_forward_LCG(uint64_t seed, uint64_t n)
{
	const uint64_t m = 9223372036854775808ULL;
	uint64_t a = 2806196910506780709ULL;
	uint64_t c = 1ULL;

	n %= m;

	uint64_t a_new = 1ULL;
	uint64_t c_new = 0ULL;

	while( n > 0 )
	{
		if( n & 1ULL )
		{
			a_new = a_new * a;
			c_new = c_new * a + c;
		}
		c = c * (a + 1ULL);
		a = a * a;
		n = n >> 1ULL;
	}

	return (a_new * seed + c_new) % m;
}

RSComplex c_add( RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r + B.r;
	C.i = A.i + B.i;
	return C;
}

RSComplex c_sub( RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r - B.r;
	C.i = A.i - B.i;
	return C;
}

RSComplex c_mul( RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	C.r = (a*c) - (b*d);
	C.i = (a*d) + (b*c);
	return C;
}

RSComplex c_div( RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	double denom = c*c + d*d;
	C.r = ((a*c) + (b*d)) / denom;
	C.i = ((b*c) - (a*d)) / denom;
	return C;
}

double c_abs( RSComplex A)
{
	return sqrt(A.r*A.r + A.i*A.i);
}

RSComplex fast_cexp( RSComplex z )
{
	double x = z.r;
	double y = z.i;

	double t1 = fast_exp(x);
	double t2 = cos(y);
	double t3 = sin(y);
	RSComplex t4 = {t2, t3};
	RSComplex t5 = {t1, 0};
	return c_mul(t5, t4);
}

void calculate_sig_T( int nuc, double E, Input input, SimulationData data, RSComplex * sigTfactors )
{
	double phi;

	for( int i = 0; i < 4; i++ )
	{
		phi = data.pseudo_K0RS[nuc * input.numL + i] * sqrt(E);

		if( i == 1 )
			phi = phi - (-atan(phi));
		else if( i == 2 )
			phi = phi - (atan(3.0 * phi / (3.0 - phi*phi)));
		else if( i == 3 )
			phi = phi - (atan(phi*(15.0-phi*phi)/(15.0-6.0*phi*phi)));

		phi = phi * 2.0;

		sigTfactors[i].r = cos(phi);
		sigTfactors[i].i = -sin(phi);
	}
}

