unsigned long long run_event_based_simulation(Inputs in, SimulationData SD, int mype)
{
	double start = get_time();

	int * verification_array_host = (int *) malloc( in.lookups * sizeof(int));
	assert(verification_array_host != NULL);

	print_translated_device_info();

	double stop = get_time();
	if( mype == 0) printf("OpenCL initialization time: %.3lf seconds\n", stop-start);
	start = stop;

	if( mype == 0 )
	{
		border_print();
		center_print("SIMULATION", 79);
		border_print();
	}

	if( mype == 0) printf("Running event based simulation...\n");

	#ifdef OPENMP
	#pragma omp parallel for schedule(static)
	#endif
	for( int i = 0; i < in.lookups; i++ )
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t) i);

		double p_energy = LCG_random_double(&seed);
		int mat         = pick_mat(&seed);

		double macro_xs_vector[5] = {0};

		calculate_macro_xs(
			p_energy,
			mat,
			in.n_isotopes,
			in.n_gridpoints,
			SD.num_nucs,
			SD.concs,
			SD.unionized_energy_array,
			SD.index_grid,
			SD.nuclide_grid,
			SD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			SD.max_num_nucs
		);

		double max = -1.0;
		int max_idx = 0;
		for(int j = 0; j < 5; j++ )
		{
			if( macro_xs_vector[j] > max )
			{
				max = macro_xs_vector[j];
				max_idx = j;
			}
		}
		verification_array_host[i] = max_idx+1;
	}

	stop = get_time();

	if( mype == 0) printf("Reducing verification value...\n");

	unsigned long long verification = 0;

	for( int l = 0; l < in.lookups; l++ )
		verification += verification_array_host[l];

	xsbench_last_sim_runtime = stop-start;
	if( mype == 0) printf("Simulation + Verification Reduction Runtime: %.3lf seconds\n", xsbench_last_sim_runtime);

	free(verification_array_host);

	return verification;
}

uint64_t fast_forward_LCG(uint64_t seed, uint64_t n)
{
	const uint64_t m = 9223372036854775808ULL;
	uint64_t a = 2806196910506780709ULL;
	uint64_t c = 1ULL;

	n = n % m;

	uint64_t a_new = 1ULL;
	uint64_t c_new = 0ULL;

	while(n > 0)
	{
		if(n & 1ULL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1ULL);
		a *= a;

		n >>= 1ULL;
	}

	return (a_new * seed + c_new) % m;
}

double LCG_random_double(uint64_t * seed)
{
	const uint64_t m = 9223372036854775808ULL;
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	*seed = (a * (*seed) + c) % m;
	return (double) (*seed) / (double) m;
}

int pick_mat( uint64_t * seed )
{
	double dist[12];
	dist[0]  = 0.140;
	dist[1]  = 0.052;
	dist[2]  = 0.275;
	dist[3]  = 0.134;
	dist[4]  = 0.154;
	dist[5]  = 0.064;
	dist[6]  = 0.066;
	dist[7]  = 0.055;
	dist[8]  = 0.008;
	dist[9]  = 0.015;
	dist[10] = 0.025;
	dist[11] = 0.013;

	double roll = LCG_random_double(seed);

	for( int i = 0; i < 12; i++ )
	{
		double running = 0;
		for( int j = i; j > 0; j-- )
			running += dist[j];
		if( roll < running )
			return i;
	}

	return 0;
}

long grid_search( long n, double quarry, double * restrict A)
{
	long lowerLimit = 0;
	long upperLimit = n-1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint] > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

long grid_search_nuclide( long n, double quarry, NuclideGridPoint * A, long low, long high)
{
	(void) n;
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint].energy > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

void calculate_micro_xs( double p_energy, int nuc, long n_isotopes,
                         long n_gridpoints,
                         double * restrict egrid, int * restrict index_data,
                         NuclideGridPoint * restrict nuclide_grids,
                         long idx, double * restrict xs_vector, int grid_type, int hash_bins )
{
	double f;
	NuclideGridPoint * low, * high;

	if( grid_type == NUCLIDE )
	{
		idx = grid_search_nuclide( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], 0, n_gridpoints-1);

		if( idx == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + idx - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + idx];
	}
	else if( grid_type == UNIONIZED)
	{
		if( index_data[idx * n_isotopes + nuc] == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc] - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc]];
	}
	else
